/** Get all lessons for a subject, in book sequence order */
export function getKnttLessons(subjectCode) {
  return KNTT_LESSON_POOL[subjectCode] || [];
}

/**
 * Get N lessons for a subject starting near a given day.
 * Wraps around so the pool never runs out.
 */
export function getKnttLessonsForDay(subjectCode, dayNumber, count = 1) {
  const pool = KNTT_LESSON_POOL[subjectCode] || [];
  if (pool.length === 0) return [];
  const start = (dayNumber - 1) % pool.length;
  const result = [];
  for (let i = 0; i < count; i++) {
    result.push(pool[(start + i) % pool.length]);
  }
  return result;
}

/**
 * Format a source citation for display in explanation text.
 * e.g. "Tiếng Việt 4 - Tập một (KNTT), tr.8 — Bài 1: Điều kì diệu — Đọc: Danh từ"
 */
export function formatSourceCitation(source) {
  if (!source) return '';
  const parts = [source.book];
  if (source.page) parts.push('tr.' + source.page);
  if (source.unit) parts.push(source.unit);
  if (source.lesson) parts.push(source.lesson);
  if (source.skill) parts.push(source.skill);
  return parts.join(' — ');
}